mapper.select:
SELECT '销售单' as type, f.name as frame, c.name as customer, DATE_FORMAT(s.time, '%Y-%m-%d') as time, s.number as number, s.total as total, (s.total - s.actual) as discount, s.actual as actual, IFNULL(cost_sum.total_cost, 0) as buy, (s.actual - IFNULL(cost_sum.total_cost, 0)) as gross_profit, CASE WHEN s.actual > 0 THEN ROUND(((s.actual - IFNULL(cost_sum.total_cost, 0)) / s.actual * 100), 2) ELSE 0 END as gross_profit_margin, IFNULL(cost_table.money, 0) as cost, (s.actual - IFNULL(cost_sum.total_cost, 0) - IFNULL(cost_table.money, 0)) as net_profit, CASE WHEN s.actual > 0 THEN ROUND(((s.actual - IFNULL(cost_sum.total_cost, 0) - IFNULL(cost_table.money, 0)) / s.actual * 100), 2) ELSE 0 END as net_profit_margin, IFNULL(bill_sum.verification_money, 0) as money, s.nucleus as nucleus, u.name as user, p.name as people, s.data as data FROM sell s LEFT JOIN frame f ON s.frame = f.id LEFT JOIN customer c ON s.customer = c.id LEFT JOIN user u ON s.user = u.id LEFT JOIN people p ON s.people = p.id LEFT JOIN ( SELECT si.pid, SUM(si.nums * g.buy) as total_cost FROM sell_info si JOIN goods g ON si.goods = g.id GROUP BY si.pid ) cost_sum ON s.id = cost_sum.pid LEFT JOIN ( SELECT pid, SUM(money) as verification_money FROM sell_bill GROUP BY pid ) bill_sum ON s.id = bill_sum.pid LEFT JOIN ( SELECT class, SUM(money) as money FROM cost WHERE type = 'sell' GROUP BY class ) cost_table ON s.id = cost_table.class WHERE s.examine = 1
AND s.customer = #{query.customer}
AND s.number LIKE CONCAT('%', #{query.number}, '%')
AND DATE(s.time) >= #{query.beginTime}
AND DATE(s.time) <= #{query.leftTime}
AND s.user = #{query.user}
AND s.people = #{query.people}
AND '销售单' = #{query.type}
ORDER BY s.time DESC

SELECT '销售单' as type, f.name as frame, c.name as customer, DATE_FORMAT(s.time, '%Y-%m-%d') as time, s.number as number, s.data as data,
g.name as goods_name, si.attr as attr, si.unit as unit, CAST(si.price AS CHAR) as price, CAST(si.nums AS CHAR) as nums, si.dsc as discount_info, si.total as total_info, si.tax as tax, si.tpt as tpt,
(si.nums * g.buy) as goods_buy, (si.total - (si.nums * g.buy)) as goods_gross_profit, CASE WHEN si.total > 0 THEN ROUND(((si.total - (si.nums * g.buy)) / si.total * 100), 2) ELSE 0 END as goods_gross_profit_margin,
s.total as total, (s.total - s.actual) as discount, s.actual as actual,
IFNULL(cost_sum.total_cost, 0) as buy, (s.actual - IFNULL(cost_sum.total_cost, 0)) as gross_profit, CASE WHEN s.actual > 0 THEN ROUND(((s.actual - IFNULL(cost_sum.total_cost, 0)) / s.actual * 100), 2) ELSE 0 END as gross_profit_margin, IFNULL(cost_table.money, 0) as cost, (s.actual - IFNULL(cost_sum.total_cost, 0) - IFNULL(cost_table.money, 0)) as net_profit, CASE WHEN s.actual > 0 THEN ROUND(((s.actual - IFNULL(cost_sum.total_cost, 0) - IFNULL(cost_table.money, 0)) / s.actual * 100), 2) ELSE 0 END as net_profit_margin,
IFNULL(bill_sum.verification_money, 0) as money, s.nucleus as nucleus,
u.name as user, p.name as people
FROM sell s INNER JOIN sell_info si ON s.id = si.pid INNER JOIN goods g ON si.goods = g.id LEFT JOIN frame f ON s.frame = f.id LEFT JOIN customer c ON s.customer = c.id LEFT JOIN user u ON s.user = u.id LEFT JOIN people p ON s.people = p.id LEFT JOIN ( SELECT si.pid, SUM(si.nums * g.buy) as total_cost FROM sell_info si JOIN goods g ON si.goods = g.id GROUP BY si.pid ) cost_sum ON s.id = cost_sum.pid LEFT JOIN ( SELECT pid, SUM(money) as verification_money FROM sell_bill GROUP BY pid ) bill_sum ON s.id = bill_sum.pid LEFT JOIN ( SELECT class, SUM(money) as money FROM cost WHERE type = 'sell' GROUP BY class ) cost_table ON s.id = cost_table.class WHERE s.examine = 1
AND s.customer = #{query.customer}
AND s.number LIKE CONCAT('%', #{query.number}, '%')
AND DATE(s.time) >= #{query.beginTime}
AND DATE(s.time) <= #{query.leftTime}
AND s.user = #{query.user}
AND s.people = #{query.people}
AND '销售单' = #{query.type}
ORDER BY s.time DESC, s.number, g.name
